import httpx, time, json
from langflow.custom import Component
from langflow.io import MessageTextInput, Output
from langflow.schema.message import Message

class PollJob(Component):
    display_name = 'Poll Scrape Job'
    description = 'Poll job status until complete. Returns final result.'
    inputs = [MessageTextInput(name='job_response', display_name='Job Response')]
    outputs = [Output(name='result', display_name='Result', method='poll')]

    SCRAPER_URL = 'http://playwright-scraper:8400'
    MAX_WAIT = 600   # 10 minutes
    INTERVAL = 5     # poll every 5 seconds

    def poll(self) -> Message:
        try:
            data = json.loads(self.job_response.text if hasattr(self.job_response, 'text') else str(self.job_response))
            job_id = data.get('job_id')
            if not job_id:
                return Message(text=json.dumps({'error': 'No job_id in response', 'raw': str(data)}))

            waited = 0
            while waited < self.MAX_WAIT:
                r = httpx.get(f'{self.SCRAPER_URL}/status/{job_id}', timeout=10)
                status = r.json()
                if status.get('status') in ('complete', 'failed'):
                    return Message(text=json.dumps(status, indent=2))
                time.sleep(self.INTERVAL)
                waited += self.INTERVAL

            return Message(text=json.dumps({'error': 'Timeout waiting for scrape job', 'job_id': job_id}))
        except Exception as e:
            return Message(text=json.dumps({'error': str(e)}))
